#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vUv = vUvOriginal;

    // Laser-Strahlen von verschiedenen Punkten
    float laser_intensity = 0;

    // Zentrale Laserpunkte
    vec2 laser_center1 = vec2(0.2 + sin(uTime*1.3)*0.1, 0.3 + cos(uTime*0.9)*0.1);
    vec2 laser_center2 = vec2(0.8 + sin(uTime*1.7)*0.1, 0.7 + cos(uTime*1.1)*0.1);
    vec2 laser_center3 = vec2(0.5 + sin(uTime*2.1)*0.15, 0.2 + cos(uTime*1.5)*0.1);

    // Strahleffekte zu verschiedenen Punkten
    for(int i = 0; i < 8; i++)
    {
        float angle = (float)i * 0.785 + uTime * 0.5 + audioLowSmooth * 2.0;
        vec2 direction = vec2(cos(angle), sin(angle));

        // Strahl von Zentrum 1
        float beam_dist1 = abs(dot(vUv - laser_center1, vec2(-direction.y, direction.x)));
        float beam_length1 = dot(vUv - laser_center1, direction);
        if(beam_length1 > 0 && beam_length1 < 1.5)
        {
            laser_intensity += (1.0 / (beam_dist1 * 100 + 1)) * (1 - beam_length1/1.5);
        }

        // Strahl von Zentrum 2
        float beam_dist2 = abs(dot(vUv - laser_center2, vec2(-direction.y, direction.x)));
        float beam_length2 = dot(vUv - laser_center2, direction);
        if(beam_length2 > 0 && beam_length2 < 1.2)
        {
            laser_intensity += (1.0 / (beam_dist2 * 80 + 1)) * (1 - beam_length2/1.2);
        }
    }

    // Rotierende Fächer
    float fan_angle = uTime * 1.5 + audioHighSmooth * 3.0;
    vec2 fan_center = vec2(0.5, 0.8);
    vec2 fan_dir = vUv - fan_center;
    float fan_dist = length(fan_dir);
    float fan_angle_pos = atan(fan_dir.y, fan_dir.x);

    // Mehrere Fächerstrahlen
    for(int j = 0; j < 5; j++)
    {
        float sector_angle = fan_angle + (float)j * 1.256;
        float angle_diff = abs(fan_angle_pos - sector_angle);
        angle_diff = min(angle_diff, 6.283 - angle_diff);

        if(angle_diff < 0.1 && fan_dist < 0.8)
        {
            laser_intensity += (1.0 / (angle_diff * 50 + 1)) * (1 - fan_dist/0.8);
        }
    }

    // Kreisförmige Laserpunkte
    vec2 circle_center1 = vec2(0.3 + sin(uTime*2.3)*0.2, 0.6 + cos(uTime*1.8)*0.15);
    vec2 circle_center2 = vec2(0.7 + sin(uTime*1.9)*0.15, 0.4 + cos(uTime*2.2)*0.2);

    float circle_dist1 = length(vUv - circle_center1);
    float circle_dist2 = length(vUv - circle_center2);

    // Pulsende Kreise
    float circle_pulse = 0.02 + audioLowSmooth * 0.01;
    if(abs(circle_dist1 - 0.1) < circle_pulse)
        laser_intensity += 2.0 / (abs(circle_dist1 - 0.1) * 200 + 1);
    if(abs(circle_dist2 - 0.08) < circle_pulse)
        laser_intensity += 2.0 / (abs(circle_dist2 - 0.08) * 200 + 1);

    // Scanning-Linien
    float scan_y = 0.5 + sin(uTime * 3.0 + audioMidSmooth * 2.0) * 0.4;
    float scan_dist = abs(vUv.y - scan_y);
    if(scan_dist < 0.002)
        laser_intensity += 1.5;

    // Farbgebung für verschiedene Laser-Typen
    ret.r = laser_intensity * (0.8 + sin(uTime*3.0)*0.2);  // Rot
    ret.g = laser_intensity * 0.3 * (0.5 + cos(uTime*2.5)*0.5);  // Wenig Grün
    ret.b = laser_intensity * (0.6 + sin(uTime*4.0)*0.4);  // Blau

    // Intensitätsverstärkung basierend auf Musik
    ret.rgb *= (1.0 + q1 * 2.0);


  fragColor = ret;
}

